-- @Bean(name = "econova-server")
-- Migration script generated by Ebean
-- This is the initial migration to create all tables

-- Disable foreign key checks during table creation
SET FOREIGN_KEY_CHECKS FALSE;

-- Table: account (Cuentas Contables)
CREATE TABLE IF NOT EXISTS account (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    code VARCHAR(50) NOT NULL UNIQUE,
    name VARCHAR(255) NOT NULL,
    account_type VARCHAR(50) NOT NULL,
    parent_id BIGINT,
    level INTEGER NOT NULL DEFAULT 1,
    active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (parent_id) REFERENCES account(id) ON DELETE SET NULL
);

-- Table: accounting_period (Períodos Contables)
CREATE TABLE IF NOT EXISTS accounting_period (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    year INTEGER NOT NULL,
    month INTEGER NOT NULL,
    status VARCHAR(20) NOT NULL DEFAULT 'OPEN',
    start_date DATE NOT NULL,
    end_date DATE NOT NULL,
    closed_at TIMESTAMP,
    closed_by VARCHAR(100),
    locked_at TIMESTAMP,
    locked_by VARCHAR(100),
    UNIQUE KEY unique_year_month (year, month)
);

-- Table: transaction (Comprobantes/Asientos Contables)
CREATE TABLE IF NOT EXISTS transaction (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    voucher_number VARCHAR(50) NOT NULL UNIQUE,
    document_number VARCHAR(50),
    description TEXT NOT NULL,
    transaction_date DATE NOT NULL,
    posting_date DATE,
    period_year INTEGER NOT NULL,
    period_month INTEGER NOT NULL,
    total_debit DECIMAL(19,4) DEFAULT 0,
    total_credit DECIMAL(19,4) DEFAULT 0,
    posted BOOLEAN DEFAULT FALSE,
    posted_by VARCHAR(100),
    posted_date TIMESTAMP,
    cancelled BOOLEAN DEFAULT FALSE,
    cancelled_by VARCHAR(100),
    cancelled_date TIMESTAMP,
    cancellation_reason TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    created_by VARCHAR(100),
    INDEX idx_period (period_year, period_month),
    INDEX idx_posted (posted),
    INDEX idx_transaction_date (transaction_date)
);

-- Table: transaction_entry (Partidas/Asientos Individuales)
CREATE TABLE IF NOT EXISTS transaction_entry (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    transaction_id BIGINT NOT NULL,
    account_id BIGINT NOT NULL,
    debit_amount DECIMAL(19,4) DEFAULT 0,
    credit_amount DECIMAL(19,4) DEFAULT 0,
    description TEXT,
    cost_center VARCHAR(100),
    third_party_id BIGINT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (transaction_id) REFERENCES transaction(id) ON DELETE CASCADE,
    FOREIGN KEY (account_id) REFERENCES account(id),
    INDEX idx_transaction (transaction_id),
    INDEX idx_account (account_id)
);

-- Table: audit_log (Registro de Auditoría)
CREATE TABLE IF NOT EXISTS audit_log (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    entity_name VARCHAR(100) NOT NULL,
    entity_id BIGINT NOT NULL,
    action VARCHAR(20) NOT NULL,
    old_values TEXT,
    new_values TEXT,
    user_name VARCHAR(100),
    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    INDEX idx_entity (entity_name, entity_id),
    INDEX idx_timestamp (timestamp)
);

-- Table: billing_series (Series de Facturación)
CREATE TABLE IF NOT EXISTS billing_series (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    series_code VARCHAR(20) NOT NULL UNIQUE,
    description VARCHAR(255),
    prefix VARCHAR(10),
    current_number INTEGER DEFAULT 0,
    active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Table: fixed_asset (Activos Fijos)
CREATE TABLE IF NOT EXISTS fixed_asset (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    code VARCHAR(50) NOT NULL UNIQUE,
    name VARCHAR(255) NOT NULL,
    acquisition_date DATE NOT NULL,
    acquisition_value DECIMAL(19,4) NOT NULL,
    useful_life_months INTEGER NOT NULL,
    depreciation_method VARCHAR(50) DEFAULT 'STRAIGHT_LINE',
    accumulated_depreciation DECIMAL(19,4) DEFAULT 0,
    net_book_value DECIMAL(19,4),
    status VARCHAR(20) DEFAULT 'ACTIVE',
    account_id BIGINT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (account_id) REFERENCES account(id)
);

-- Table: depreciation_record (Registro de Depreciación)
CREATE TABLE IF NOT EXISTS depreciation_record (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    fixed_asset_id BIGINT NOT NULL,
    year INTEGER NOT NULL,
    month INTEGER NOT NULL,
    depreciation_amount DECIMAL(19,4) NOT NULL,
    accumulated_depreciation DECIMAL(19,4) NOT NULL,
    net_book_value DECIMAL(19,4) NOT NULL,
    processing_date DATE,
    posted BOOLEAN DEFAULT FALSE,
    transaction_id BIGINT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (fixed_asset_id) REFERENCES fixed_asset(id),
    FOREIGN KEY (transaction_id) REFERENCES transaction(id),
    UNIQUE KEY unique_asset_year_month (fixed_asset_id, year, month)
);

-- Table: inventory_item (Items de Inventario)
CREATE TABLE IF NOT EXISTS inventory_item (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    code VARCHAR(50) NOT NULL UNIQUE,
    name VARCHAR(255) NOT NULL,
    description TEXT,
    unit_of_measure VARCHAR(50) NOT NULL,
    unit_cost DECIMAL(19,4) DEFAULT 0,
    quantity_on_hand DECIMAL(19,4) DEFAULT 0,
    minimum_quantity DECIMAL(19,4) DEFAULT 0,
    maximum_quantity DECIMAL(19,4),
    account_id BIGINT,
    active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (account_id) REFERENCES account(id)
);

-- Table: inventory_movement (Movimientos de Inventario)
CREATE TABLE IF NOT EXISTS inventory_movement (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    item_id BIGINT NOT NULL,
    movement_type VARCHAR(20) NOT NULL,
    quantity DECIMAL(19,4) NOT NULL,
    unit_cost DECIMAL(19,4),
    total_cost DECIMAL(19,4),
    reference_type VARCHAR(50),
    reference_id BIGINT,
    movement_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    notes TEXT,
    created_by VARCHAR(100),
    FOREIGN KEY (item_id) REFERENCES inventory_item(id),
    INDEX idx_item (item_id),
    INDEX idx_movement_date (movement_date)
);

-- Enable foreign key checks after table creation
SET FOREIGN_KEY_CHECKS TRUE;

